const PROMPTS_BY_ERA = {
  Debut: [
    "where are you starting from today, honestly?",
    "what made it possible for you to show up at all?",
    "if today had a volume knob, where would it be set?",
    "what's one early warning sign you tend to miss when you're overwhelmed?",
    "what's one small 'return' action that helps you stabilize?",
    "what story do you tell yourself when you miss something?",
    "if you didn't have to explain yourself, what would you return to?",
  ],
  Fearless: [
    "what are you afraid of messing up right now?",
    "where are you showing courage even if it doesn't feel brave?",
    "what would it look like to move forward with fear instead of waiting for it to leave?",
    "where are you expecting proof instead of progress?",
    "what does your inner voice say after a setback?",
    "what would a shame-neutral response sound like?",
  ],
  "Speak Now": [
    "where do you usually stay quiet to keep the peace?",
    "what feels hardest to say out loud right now?",
    "what need have you been minimizing?",
    "what boundary feels overdue?",
    "where do you over-explain to feel safe?",
    "what would one clear sentence sound like?",
  ],
  Red: [
    "what emotion feels loudest right now?",
    "if your emotions had a weather report today, what would it be?",
    "what feeling do you usually try to avoid?",
    "what emotional pattern are you starting to notice?",
    "what feels unresolved emotionally?",
  ],
  "1989": [
    "what change are you considering right now?",
    "what coping strategy has outlived its usefulness?",
    "how do you define success right now? whose definition are you trying to meet?",
    "what's one small experiment you're curious about?",
  ],
  Reputation: [
    "where are you tempted to explain yourself right now?",
    "what feels safer to keep private?",
    "what feels broken that you want to rush to fix?",
    "where do you doubt yourself most right now?",
    "where do you feel pressure to prove you've changed?",
  ],
  Lover: [
    "where do you notice calm trying to show up?",
    "what part of you doesn't trust ease yet?",
    "what are you still punishing yourself for?",
    "what part of your life feels livable right now?",
    "where do you wait for things to go wrong?",
  ],
  "Folklore/Evermore": [
    "what feels quieter in your life right now?",
    "what story about yourself is softening?",
    "where are you tempted to push past your limits?",
    "what feels 'uneventful' right now? what stability are you underrating?",
  ],
  Midnights: [
    "what thought shows up on repeat lately?",
    "what thought pressures you to act quickly?",
    "what does your inner critic say most often?",
    "what keeps your mind awake?",
  ],
  TTPD: [
    "what truth feels heavy to keep holding?",
    "what loss are you still carrying?",
    "what do you tend to overshare when emotions spike?",
    "what chapter is ready to close?",
  ],
  Showgirl: [
    "where are you still making yourself smaller?",
    "what pleasure do you hesitate to allow?",
    "what win are you tempted to downplay?",
  ],
};

function PromptsView({ era, eraId, setEraId, weekInEra }) {
  const weekData = ERA_WEEKS[era.name]?.[weekInEra - 1];
  const weekKey = `${era.name}-${weekInEra}`;
  const weekSpecific = WEEK_PROMPTS[weekKey];
  const fallback = PROMPTS_BY_ERA[era.name] || [];
  const prompts = weekSpecific || fallback;
  const [selected, setSelected] = useState(null);
  const [response, setResponse] = useState("");

  return (
    <div style={{ padding: "20px 22px 100px" }}>
      <div style={{ marginBottom: 24 }}>
        <p style={styles.greeting}>{era.emoji} {era.name}</p>
        <p style={{ ...styles.greetingSub, color: era.color }}>{era.subtitle}</p>
        {weekData && (
          <div style={{ marginTop: 14, padding: "12px 14px", background: `${era.color}12`, borderRadius: 10, borderLeft: `2px solid ${era.color}` }}>
            <p style={{ ...styles.eraLabel, color: era.color, margin: 0 }}>week {weekInEra}</p>
            <p style={{ fontFamily: "'Fraunces', serif", fontSize: 16, fontWeight: 500, margin: "2px 0 4px" }}>{weekData.theme}</p>
            <p style={{ fontSize: 12, color: "#6B6B6B", fontStyle: "italic", margin: 0, lineHeight: 1.4 }}>"{weekData.reframe}"</p>
          </div>
        )}
      </div>

      <p style={styles.sectionLabel}>journaling prompts</p>
      <p style={{ fontSize: 13, color: "#6B6B6B", marginTop: -4, marginBottom: 16 }}>
        pick one. or don't. there's no wrong way to do this.
      </p>

      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {prompts.map((p, i) => (
          <button
            key={i}
            onClick={() => setSelected(p)}
            style={{
              ...styles.promptCard,
              borderLeft: `3px solid ${era.color}`,
              background: selected === p ? `${era.color}10` : "#fff",
            }}
          >
            {p}
          </button>
        ))}
      </div>

      {selected && (
        <div style={{ marginTop: 20 }}>
          <p style={styles.sectionLabel}>your response</p>
          <textarea
            value={response}
            onChange={(e) => setResponse(e.target.value)}
            placeholder="write as much or as little as you want. just for you."
            style={{ ...styles.textarea, borderColor: era.color }}
            rows={6}
          />
        </div>
      )}
    </div>
  );
}

// ============================================================
// PROGRESS
// ============================================================
function ProgressView({ era, eraId, weekInEra, streak, checkIns }) {
  const erasComplete = eraId;
  const totalEras = ERAS.length;

  return (
    <div style={{ padding: "20px 22px 100px" }}>
      <div style={{ marginBottom: 28 }}>
        <p style={styles.greeting}>your steps</p>
        <p style={styles.greetingSub}>quietly, consistently, on your own terms.</p>
      </div>

      {/* Streak */}
      <div style={{ ...styles.statCard, background: `linear-gradient(135deg, ${era.color}22, ${era.color}08)` }}>
        <p style={styles.statLabel}>check-in streak</p>
        <p style={{ ...styles.statBig, color: era.color }}>
          {streak}
          <span style={{ fontSize: 16, fontWeight: 400, color: "#6B6B6B", marginLeft: 6 }}>
            {streak === 1 ? "day" : "days"}
          </span>
        </p>
        <p style={{ fontSize: 12, color: "#6B6B6B", marginTop: 2 }}>
          {streak === 0 ? "start whenever you want." : "you don't have to be perfect to keep going."}
        </p>
      </div>

      {/* Era progress */}
      <div style={styles.section}>
        <p style={styles.sectionLabel}>era progress</p>
        <div style={{ display: "flex", flexDirection: "column", gap: 8, marginTop: 10 }}>
          {ERAS.map((e, i) => {
            const isCurrent = i === eraId;
            const isPast = i < eraId;
            return (
              <div
                key={e.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 12,
                  padding: "10px 14px",
                  background: isCurrent ? `${e.color}18` : "transparent",
                  borderRadius: 10,
                  border: isCurrent ? `1px solid ${e.color}50` : "1px solid transparent",
                  opacity: isPast ? 0.6 : 1,
                }}
              >
                <div
                  style={{
                    width: 24,
                    height: 24,
                    borderRadius: "50%",
                    background: isPast || isCurrent ? e.color : "#EDE6DC",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    fontSize: 11,
                    color: "#fff",
                    flexShrink: 0,
                  }}
                >
                  {isPast ? "✓" : isCurrent ? "•" : ""}
                </div>
                <div style={{ flex: 1 }}>
                  <p style={{ margin: 0, fontFamily: "'Fraunces', serif", fontSize: 15, fontWeight: 500 }}>
                    {e.emoji} {e.name}
                  </p>
                  <p style={{ margin: 0, fontSize: 11, color: "#6B6B6B" }}>
                    {isCurrent ? `week ${weekInEra} of 5 · ${e.subtitle}` : e.subtitle}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Recent check-ins */}
      <div style={styles.section}>
        <p style={styles.sectionLabel}>recent check-ins</p>
        {checkIns.length === 0 ? (
          <p style={{ fontSize: 13, color: "#6B6B6B" }}>no check-ins yet. no pressure.</p>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 6, marginTop: 8 }}>
            {checkIns
              .slice(-7)
              .reverse()
              .map((c, i) => (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    padding: "8px 12px",
                    background: "#fff",
                    borderRadius: 8,
                    border: "1px solid #EDE6DC",
                    fontSize: 13,
                  }}
                >
                  <span style={{ color: "#6B6B6B" }}>{new Date(c.date).toLocaleDateString([], { month: "short", day: "numeric" })}</span>
                  <span style={{ fontFamily: "'Fraunces', serif", fontStyle: "italic" }}>{c.mood}</span>
                </div>
              ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ============================================================
// TAB BAR
// ============================================================
function TabBar({ tab, setTab, eraColor }) {
  const tabs = [
    { id: "home", label: "today", icon: Home },
    { id: "chat", label: "talk", icon: Sparkles },
    { id: "prompts", label: "reflect", icon: BookOpen },
    { id: "progress", label: "steps", icon: Heart },
  ];

  return (
    <div style={styles.tabBar}>
      {tabs.map((t) => {
        const Icon = t.icon;
        const active = tab === t.id;
        return (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            style={{
              ...styles.tabBtn,
              color: active ? eraColor : "#9B9B9B",
            }}
          >
            <Icon size={20} strokeWidth={active ? 2.4 : 1.8} />
            <span style={{ fontSize: 10, marginTop: 3, fontWeight: active ? 600 : 400 }}>{t.label}</span>
          </button>
        );
      })}
    </div>
  );
}

